INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'La parole de Allâh', 'Baqillani', 'كَـــــانَ اللهُ وَلَــــمْ يَــــكُــــنْ شَــىءٌ غَــيْـــرُهُ', '', '', '[ce qui a pour sens ] : «Allâh existe de toute éternité et rien d’autre que Lui n’est de toute éternité » . Ce hadîth est une réplique suffisante aux propos des wahhabites. En effet ni les sons, ni les lettres, ni les voix, ni autre qu’eux n’existent de toute éternité avec Allâh. Alors que les attributs de Allâh sont de toute éternité sans début ni fin.
– Voir d’autres citations de savants au sujet de la parole de Allâh : ici .', 'al insaf, al-bâqillâni, la parole, الإنصاف'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'كَـــــانَ اللهُ وَلَــــمْ يَــــكُــــنْ شَــىءٌ غَــيْـــرُهُ');

