INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'le jugement de celui qui ne prie pas', 'Abou Dawoud', 'خَمسُ صَلَواتٍ كَتَبهنَّ اللهُ على العبادِ، فمن جاء بهنَّ لم يُضَيِّعْ منهنَّ شَيئًا استِخفافًا بحَقِّهنَّ، كان له عند الله عَهدٌ أن يُدخِلَه الجنَّةَ، ومن لم يأتِ بهنَّ فليس له عند اللهِ عَهدٌ؛ إن شاء عَذَّبه، وإن شاء أدخَلَه الجنَّةَ', '', '', 'Dans son célèbre recueil de hadîth, l’Imâm Aboû Dâwoûd rapporte que le Messager de Allâh (صلى الله عليه وسلم) a dit :
Sens en français : « Ce sont cinq prières que Allâh a prescrites pour les esclaves. Celui qui les accomplit, sans en diminuer quoi que ce soit par manque de considération envers leurs mérites, a une promesse de la part de Allâh de le faire entrer au Paradis. Quant à celui qui ne les aura pas accomplies, il n’aura pas de promesse de la part de Allâh : s’Il veut, Il le châtiera [- par Justice de Sa part -] et s’Il veut, Il le fera entrer au Paradis [- par miséricorde de Sa part, c’est-à-dire qu’Il lui pardonnera -] »
Informations utiles :
– L’Imâm, le Hâfidh (spécialiste de la science du hadîth) Aboû Dâwoûd Soulaymân Ibn Al-Ach’ath As-Sijistâni est né en 202 et est décédé en 275 de l’Hégire (رحمه الله), c’est-à-dire il y a plus de 1160 ans. Il fait parti des grands savants du hadîth, et son recueil « Sounan Abî Dâwoûd » fait partie des ouvrages les plus célèbres dans cette science.
– Ce hadîth authentique (sahîh) est rapporté par l’Imâm Aboû Dawoûd, mais aussi par :
L’Imâm An-Naçâ-i dans ses Sounan.
L’Imâm Ibn Mâjah dans ses Sounan.
L’Imâm Ahmad dans son Mousnad.
L’Imâm Mâlik dans son Mouwatta.
L’Imâm Al-Bayhaqi dans As-Sounan Al-Koubrâ.
L’Imâm Ad-Dârimi dans ses Sounan.
Et d’autres encore…
– Le Chaykh Az-Zourqâni Al-Mâliki Al-Azhari a dit concernant ce hadîth : « Ibn Hibbân, Al-Hâkim et Ibn ‘Abdi l-Barr l’ont jugé authentique (sahîh) » [Dans son commentaire du Mouwatta].
– Dans ce hadîth, le Messager de Allâh (صلى الله عليه وسلم) nous enseigne que celui qui n’accomplit pas la prière n’est pas déclaré mécréant. En effet, il a dit au sujet de celui qui ne les accomplit pas « وإن شاء أدخَلَه الجنَّةَ » [sens en français : ] « et s’Il veut, Il le fera entrer au Paradis» , et nous savons que Allâh ne pardonne pas la mécréance de celui qui meurt sur la mécréance, et que le mécréant n’entre pas au Paradis.
– Allâh ta’âlâ dit, dans soûrat An-Niçâ / 48 :', 'abou dawoud, celui qui délaisse la prière, celui qui ne prie pas, delaissement'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'خَمسُ صَلَواتٍ كَتَبهنَّ اللهُ على العبادِ، فمن جاء بهنَّ لم يُضَيِّعْ منهنَّ شَيئًا استِخفافًا بحَقِّهنَّ، كان له عند الله عَهدٌ أن يُدخِلَه الجنَّةَ، ومن لم يأتِ بهنَّ فليس له عند اللهِ عَهدٌ؛ إن شاء عَذَّبه، وإن شاء أدخَلَه الجنَّةَ');

