Plus loin, il dit :', 'allah, aqida, aube, book'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = '{وَجَاءَ رَبُّكَ} أي أمره و قضاؤه. قاله الحسن ، وهو من باب حذف المضاف');

