INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Le Chaykh As-Soubki Al-Azhari dit qu’il est de la mécréance par unanimité de croire que Allâh est dans une direction ou qu’Il est assis sur le Trône', 'Unanimité', 'قد سألني بعض الراغبين في معرفة عقائد الدين ، والوقوف على مذهب السلف والخلف في المتشابه من الآيات والأحاديث بما نصه : ما قول السادة العلماء حفظهم الله تعالى فيمن يعتقد أن الله عز وجل له جهة !! وأنه جالس على العرش في مكان مخصوص !! ويقول : ذلك هو عقيدة السلف', '« Un de ceux qui veulent connaître la science de la religion, et s’attacher à la voie du Salaf et du Khalaf m’a interrogé au sujet de ce qui n’est pas explicite dans les versets et les hadîth, par sa parole : « Que disent les maîtres des savants, que Allâh ta’âlâ les protège, au sujet de celui qui a pour croyance que Allâh ‘azza wa jall a une direction, ou qu’Il serait assis sur le trône dans un endroit spécifique et qui dit que cela est la croyance du Salaf ?»', '', 'Dans son ouvrage «It-hâfou l-Kâ-inat bi-bayâni madh-habi s-salaf wa l-khalaf fi l-moutachâbihât » le Chaykh As-Soubki Al-Azhari a rédigé une longue fatwâ, dans laquelle il a dit :
Plus loin, il répond :', 'adh-dhahabi, al azhar, al-azhar, allah'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'قد سألني بعض الراغبين في معرفة عقائد الدين ، والوقوف على مذهب السلف والخلف في المتشابه من الآيات والأحاديث بما نصه : ما قول السادة العلماء حفظهم الله تعالى فيمن يعتقد أن الله عز وجل له جهة !! وأنه جالس على العرش في مكان مخصوص !! ويقول : ذلك هو عقيدة السلف');

