INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Chaykh As-Soubki Al-Azhari : le jugement de celui qui attribue l’endroit à Allâh', 'Soubki Al-Azhari', 'فكل من اعتقد أنه تعالى حل في مكان أو اتصل به أو بشيء من الحوادث كالعرش أوالكرسي أو السماء أو الأرض أو غير ذلك فهو كافر قطعا ، ويبطل جميع عمله من صلاة وصيام وحج وغير ذلك ، وتبين منه زوجه وعليه أن يتوب فورا ، وإذا مات على هذا الاعتقاد ـ والعياذ بالله تعالى ـ لا يغسل ولا يصلى عليه ولا يدفن في مقابر المسلمين ، ومثله في ذلك كله من صدقه في اعتقاده أعاذنا الله تعالى من شرور أنفسنا وسيئات أعمالنا ، وأما حمله الناس على أن يعتقدوا هذا الاعتقاد المكفر وقوله لهم من لم يعتقد ذلك يكون كافرا !! فهو كفر وبهتان عظيم', 'Quiconque a cru que Allâh ta’âlâ est incarné dans un endroit, ou qu’Il est en contact avec un endroit, ou avec quoi que ce soit parmi les créatures comme le trône (al-‘Arch), le piédestal (al-Koursi), le ciel, la terre ou autre que cela est catégoriquement un mécréant. Toutes les récompenses de ses actes sont annulés que ce soit sa prière, son jeûne, son pèlerinage et autres que ceux-là. Sa femme cesse d’être son épouse, il doit se repentir immédiatement [en revenant à l’Islâm par la prononciation des deux témoignages] et s’il meurt sur cette croyance, que Allâh ta’âlâ nous en préserve, il n’est pas lavé, on ne fait pas la prière funéraire en sa faveur, on ne l’enterre pas dans un cimetière de musulmans. Et sont pareils à celui-là tous ceux qui ont cru [en une telle personne] avec cette croyance, que Allâh ta’âlâ nous préserve du mal de nos âmes et de nos mauvais actes. Quant au fait d’amener les gens à croire en cela et à leur dire que ne pas croire ainsi est de la mécréance, ceci est [également] de la mécréance et une grave calomnie.', '', 'Dans son ouvrage « Ithâfou l-Kâ-inât bi-bayâni s-salaf wa l-khalaf fi l-moutachâbihât » le Chaykh As-Soubki Al-Azhari a rédigé une longue fatwâ, dans laquelle il a dit :
Informations utiles :
– Le Chaykh, le Faqîh (spécialiste de la jurisprudence), le Mouhaddith (spécialiste de la science du Hadîth) Aboû Mouhammad Mahmoûd ibnou Mouhammad ibnou Ahmad Khattâb As-Soubki Al-Azhari Al-Mâliki est né en 1274 à Soubk al-Ahad (Egypte) et il est décédé en 1352 de l’Hégire au Caire (رحمه الله) c’est-à-dire il y a plus de 80 ans. Il était l’un des Chaykh de l’Université Islamique Al-Azhar et y enseigna durant 37 ans.
– Ici, il explique de manière détaillée le jugement de celui qui croit que Allâh serait dans un endroit et les conséquences de cette mauvaise croyance.
– Dans un autre passage il précise que le fait de croire que Allâh serait dans une direction, ou de croire que Allâh serait sur le trône, cela est de la mécréance par unanimité. [ Retrouvez la citation : ici ]
– Cette fatwâ fut validée par une assemblée de savants de l’Université Islamique Al-Azhar, composée :
du Chaykh Mouhammad An-Najdi, le Chaykh des maîtres des Chafi’ites ;
du Chaykh Mouhammad Sabî’ Adh-Dhahabi, le Chaykh des maîtres Hanbalites ;
du Chaykh Mouhammad al-‘Azbi Rizq, l’enseignant des hautes études ;
du Chaykh ‘Abdoul-Hamîd ‘Ammâr, l’enseignant des hautes études ;
du Chaykh ‘Aliyy An-Nahrawi, l’enseignant des hautes études ;
du Chaykh Dousoûqi ‘AbdoulLâh Al-‘Arabi, du comité des grands savants ;
du Chaykh ‘Ali Mahfoûdh, l’enseignant dans les spécialités de Al-Azhar ;
du Chaykh Ibrâhîm ‘Ayyârah Ad-Daljamoûni, l’enseignant dans la section spécialisation de Al-Azhar ;
du Chaykh Mouhammad ‘Alyân, grand savant de Al-Azhar ;
du Chaykh Ahmad Makki, l’enseignant dans la section des spécialisations de Al-Azhar ;
et du Chaykh Mouhammad Houcayn Himdân.
– D’autres extraits de cette fatwâ sont disponible sur le site [ à retrouver : ici ].', 'adh-dhahabi, al azhar, al-azhar, allah'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'فكل من اعتقد أنه تعالى حل في مكان أو اتصل به أو بشيء من الحوادث كالعرش أوالكرسي أو السماء أو الأرض أو غير ذلك فهو كافر قطعا ، ويبطل جميع عمله من صلاة وصيام وحج وغير ذلك ، وتبين منه زوجه وعليه أن يتوب فورا ، وإذا مات على هذا الاعتقاد ـ والعياذ بالله تعالى ـ لا يغسل ولا يصلى عليه ولا يدفن في مقابر المسلمين ، ومثله في ذلك كله من صدقه في اعتقاده أعاذنا الله تعالى من شرور أنفسنا وسيئات أعمالنا ، وأما حمله الناس على أن يعتقدوا هذا الاعتقاد المكفر وقوله لهم من لم يعتقد ذلك يكون كافرا !! فهو كفر وبهتان عظيم');

