INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’Imâm Aboû Hanîfah dit que la proximité ou le fait d’être loin de Allâh n’est pas en terme de distance', 'Abou Hanifah', 'وليسَ قربُ اللهِ تعالى ولا بُعدُهُ منْ طريقِ طولِ المسافةِ وقِصَرِها و لكن على معنى الكرامةِ والهوانِ، و المطيعُ قريبٌ منهُ بلا كيفٍ، والعاصي بعيدٌ عنهُ بلا كيفٍ', 'Al-qourb (la proximité) ou al-bou’d (l’éloignement) par rapport à Allâh ta’âlâ n’est pas une proximité ou un éloignement par la voie de la distance mais cela est dans le sens de l’attribution d’honneur ou d’humiliation. L’obéissant est qarîb [hororé par Allâh] sans comment (bila kayf) et le désobéissance est ba’îd [humilié par Allâh] sans comment (bila kayf)', '', 'L’Imâm Aboû Hanîfah a dit dans son livre « Al-Fiqhou l-Akbar » (pages 326 et 327 de cette édition qui est un charh (commentaire) du livre « Al-Fiqhou l-Akbar » réalisé par le Chaykh Moullâ ‘Ali Al-Qâri, mais 4ème et 5ème pages du traité de croyance de l’Imâm Aboû Hanîfah qui est cité à la fin du livre) :
Informations utiles :
– L’Imâm, le Moujtahid Aboû Hanîfah An-Nou’mân Ibnou Thâbit, est l’un des savants du Salaf les plus réputés. Il est né en 80 et il est décédé en 150 de l’Hégire (رحمه الله). C’est-à-dire il y a plus de 1280 ans. Il est l’Imâm de l’école (madh-hab) Hanafite et il a eu l’honneur de rencontrer des compagnons du Messager de Allâh (صلى الله عليه وسلم). Retrouvez sa biographie : ici .
– Son livre « Al-Fiqh Al-Akbar » fait partie des ouvrages qu’il a écrit sur la croyance et dont les savants ont confirmé l’authenticité. L’Imâm Mourtadâ Az-Zabîdi Al-Hanafi confirme cela dans son livre «It-hâfou s-Sâdati l-Mouttaqîn», ainsi que l’Imâm Al-Kawthari Al-Hanafi et d’autres.
– Ici, l’Imâm Aboû Hanîfah explique que la proximité ou le fait d’être loin de Allâh n’est pas en terme de distance, puis il interprète en disant que cela est en termes d’honneur et d’humiliation. C’est ce qui doit être compris, entre autres, du hadîth : « أقرب ما يكون العبد من ربِّه وهو ساجد »
– La proximité et l’éloignement par la distance est impossible au sujet de Allâh. Celui qui est au sommet de la montagne ou même les anges qui portent le Trône, et celui qui est tout en bas de la vallée sont équivalents par rapport à Allâh. Car Allâh ta’âlâ est sans endroit, Il exempt de la proximité et de l’éloignement physique, c’est-à-dire la proximité et l’éloignement par la distance. Ce qui est visé par ces termes, c’est la proximité et l’éloignement de son agrément.
– C’est pour cela que l’Imâm Al-Jouwayni (رحمه الله) a dit : « Certes [le prophète] Mouhammad (صلى الله عليه وسلم) , lors de la nuit de al-Isrâ (c’est-à-dire lors du voyage nocturne et de l’ascension), n’a pas été plus proche [physiquement] de Allâh ‘azza wa jall que [le prophète] Yoûnous Ibnou Matâ lorsqu’il était dans le ventre de la baleine » [ retrouvez l’article : ici ].', 'abo hanîfah, abou hanifa, abou hanifah, abu hanifa'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'وليسَ قربُ اللهِ تعالى ولا بُعدُهُ منْ طريقِ طولِ المسافةِ وقِصَرِها و لكن على معنى الكرامةِ والهوانِ، و المطيعُ قريبٌ منهُ بلا كيفٍ، والعاصي بعيدٌ عنهُ بلا كيفٍ');

-- source: https://islamsunnite.net/limam-an-nacafi-dit-que-allah-existe-de-toute-eternite-sans-endroit-et-quil-est-exempt-du-changement/
INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’Imâm An-Naçafi dit que Allâh existe de toute éternité sans endroit et qu’Il est exempt du changement', 'Naçafi (m.710H)', 'إنه تعالى كان ولا مكان فهو على ماكان قبل خلق الـمكان ، لـم يتغير عما كان', '« Allâh ta’âlâ est de toute éternité alors qu’il n’y a pas d’endroit de toute éternité et Il est tel qu’Il est de toute éternité avant la création des endroits, Il ne change pas par rapport à ce qu’Il est de toute éternité ».', '', 'Dans son célèbre tafsîr (exégèse du Qour-ân), lors de l’explication du verset « ٱلرَّحۡمَـٰنُ عَلَى ٱلۡعَرۡشِ ٱسۡتَوَىٰ » « Ar-Rahmânou ‘ala l-‘archi stawâ » (Soûrat Taha/5), l’Imâm An-Naçafi a dit :
Informations utiles :
– L’Imâm, le Moufassir (exégète) ‘Abdou l-Lâh Ibnou Ahmad An-Naçafi, est décédé en 710 de l’Hégire, certains ayant dit en 701 de l’Hégire (رحمه الله) c’est-à-dire il y a plus de 730 ans. Il était du madh-hab (école de jurisprudence) de l’Imâm Aboû Hanîfah. Son exégèse du Qour-ân (tafsîr) est une référence en la matière.
– Ne pas le confondre avec l’ Imâm An-Naçafi (décédé en 508 H.) ou avec l’ Imâm An-Naçafi (décédé en 537 H.) (رحمها الله).
– Ici, dans son explication du verset « ٱلرَّحۡمَـٰنُ عَلَى ٱلۡعَرۡشِ ٱسۡتَوَىٰ » « Ar-Rahmânou ‘ala l-‘archi stawâ » (Soûrat Taha/5), il dit bien que Allâh existe sans endroit de toute éternité et qu’Il n’est pas concerné par le changement.
– Pour ce grand spécialiste de l’exégèse du Qour-ân, comme pour l’unanimité des musulmans, ce verset ne signifie en aucun cas que Allâh serait dans un endroit ou une direction ; contrairement à ce que croient les assimilationnistes (mouchabbihah).
– En effet l’Imâm An-Naçafi rapporte dans son tafsîr que l’istiwâ de Allâh a pour sens la domination par la toute-puissance [ voir l’article à ce sujet : ici ].', '3ala l-3arch istawa, 3ala l-3archi stawa, allah, an-naçafi'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'إنه تعالى كان ولا مكان فهو على ماكان قبل خلق الـمكان ، لـم يتغير عما كان');

-- source: https://islamsunnite.net/limam-al-kawthari-dit-que-allah-est-sans-endroit-et-ne-depend-pas-du-temps/
INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’Imâm Al-Kawthari dit que Allâh est sans endroit et ne dépend pas du temps', 'Les Hanafites', 'وتنـزيه الله سبحانه عن الـمكان والـمكانيات والزمان والزمانيات هو عقيدة أهل الحق رغم اغتياظ الـمجسمة الصرحاء', 'L’exemption de Allâh soubhânahou, de l’endroit et de ce qui est relatif aux endroits, du temps et de ce qui est relatif au temps, la voilà la croyance des gens de la vérité en dépit de la rage des anthropomorphistes (moujassimah) déclarés', '', 'L’assistant du dernier calife des musulmans, l’Imâm Al-Kawthari a dit dans son livre « Maqâlâtou l-Kawthari » (page 490 de cette édition) :
Informations utiles :
– L’Imâm, le Mouhaddith (spécialiste de la science du hadîth), le Chaykh Mouhammad Zâhid Al-Kawthari Al-Hanafi était l’assistant du dernier Calife des musulmans (le Califat a pris fin en 1924). Il était un grand savant Hanafite qui a même été appelé par certains le « Moujaddid » du siècle dernier (c’est-à-dire celui qui revitalise la science de la religion). Il est né en 1296 et il est décédé en 1371 de l’Hégire (رحمه الله), c’est-à-dire il y a plus de 70 ans.
Le Chaykh Al-Qoudâ’i Al-’Azzâmi a dit de lui : « Al-‘Allâmah (l’illustre savant) scrupuleux, qui est très intelligent, le vérificateur, l’éminent enseignant (al-Oustâdh al-Kabîr), le Chaykh Mouhammad Zâhid Al-Kawthari » [Al-Fourqân]
– Ici, il dit que le fait de croire que Allâh est exempt de l’endroit et du temps est la croyance des gens de la vérité, contrairement à ce que prétendent les anthropomorphistes, qui attribuent le corps à Allâh.', 'allah, aqida, book, califa'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'وتنـزيه الله سبحانه عن الـمكان والـمكانيات والزمان والزمانيات هو عقيدة أهل الحق رغم اغتياظ الـمجسمة الصرحاء');

