INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’ancien Moufti d’Egypte Mouhammad Haçanayn Makhloûf parle de la vision de Allâh au paradis', 'Al Azhar', 'فَيُرَى سبحانه لا في مكانٍ ولا جهةٍ ولا باتصال شعاعٍ ولا ثبوت مسافةٍ بين الرائيين وبينه تعالى بل على الوجه الذي يليق بقدسيته وجلاله سبحانه', 'Il (Allâh) sera vu soubhânahou sans qu’Il soit dans un endroit ni une direction, sans contact par un rayon lumineux ni établissement d’une distance entre ceux qui Le verront et Lui ta’âlâ mais tel qu’il est digne de Son exemption et de Sa gloire, soubhânah', '', 'Dans son livre « Moukhtasarou Charhi ‘Aqîdati Ahli l-Islâm », l’ancien Moufti d’Egypte, le Chaykh Mouhammad Haçanayn Makhloûf a dit :
Informations utiles :
– Le Moufti d’Egypte, le Chaykh Mouhammad Haçanayn Makhloûf Al-‘Adawi Al-Mâliki, est né en 1307 et il est décédé en 1410 de l’Hégire (رحمه الله). Il était également l’un des grands Chaykh de l’université Islamique « Al-Azhar » d’Egypte.
– Ici, il parle de la vision de Allâh qu’auront les musulmans lorsqu’ils seront au paradis, sans que Allâh ne soit dans un endroit ou une direction, et sans qu’il y ait une notion de distance.', 'al azhar, al-azhar, allah, aqida'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'فَيُرَى سبحانه لا في مكانٍ ولا جهةٍ ولا باتصال شعاعٍ ولا ثبوت مسافةٍ بين الرائيين وبينه تعالى بل على الوجه الذي يليق بقدسيته وجلاله سبحانه');

