INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’Imâm Ibn Hajar Al-‘Asqalâni dit que Allâh est exempt de la direction du haut et du bas', 'Les Chafi''ites', 'ولا يلزم من كون جهتي العلو والسفل مُحالاً على الله أن لا يوصف بالعلو ، لأن وصفه بالعلو من جهة الـمعنى ، والـمستحيل كون ذلك من جهة الحس، ولذلك ورد في صفته العالي والعلي والـمتعالي ، ولـم يرد ضد ذلك وإن كان قد أحاط بكل شىءٍ علـماً', '« Le fait que les deux directions du haut et du bas soient impossibles au sujet de Allâh n’implique pas qu’on ne Le qualifie pas par al-‘oulouww (l’élévation par le degré) car Son attribution par al-‘oulouww vient dans le sens figuré. Ce qui est impossible, c’est qu’il vienne dans le sens physique (c’est-à-dire l’élévation par l’endroit). C’est pourquoi il a été rapporté des textes concernant Ses attributs Al-‘Âli, Al-‘Aliyy et Al-Mouta’âli, mais il n’a pas été rapporté quelque chose qui signifie le contraire, même s’Il englobe effectivement toute chose par Sa science ».', '', 'Dans son commentaire du Sahîh de Al-Boukhâri «Fath Al-Bârî » (tome 6 page 136 de cette édition), l’Imâm Ibnou Hajar Al-‘Asqalâni a dit :
Informations utiles :
– Chaykhou l-Islâm, Amîr al-Mouminîn fi l-hadîth (le Prince des croyants dans la science du hadîth) Chihâb ad-Dîn Abou l-Fadl Ahmad Ibnou ‘Ali Ibnou Hajar Al-‘Asqalâni est né en 773 et il est décédé en 852 de l’hégire (رحمه الله) c’est-à-dire il y a plus de 590 ans. C’est un très grand spécialiste de la science du hadîth qui a écrit de nombreux ouvrages. Il est du madh-hab (Ecole de jurisprudence) de l’Imam Ach-Châfi’i. Son livre « Fath Al-Bârî » est incontournable, c’est le plus célèbre commentaire du Sahîh Al-Boukhâri. Consultez sa biographie : ici .
– Ici, le Hâfidh Ibnou Hajar dit que Allâh n’est pas concerné par les directions tel que le haut et le bas. Et il dit que « Al-‘oulouww » (l’élévation) au sujet Allâh ne vient pas dans le sens physique, c’est-à-dire que ce n’est pas une élévation par l’endroit ou la direction ; mais « Al-‘oulouww » vient dans le sens figuré, c’est-à-dire l’élévation par le degré.
– Le Messager de Allâh (صلى الله عليه وسلم) a lui même nié les directions au sujet de Allâh [ Voir l’article à ce sujet : ici ].', '3oulouww, allah, aqida, bas'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'ولا يلزم من كون جهتي العلو والسفل مُحالاً على الله أن لا يوصف بالعلو ، لأن وصفه بالعلو من جهة الـمعنى ، والـمستحيل كون ذلك من جهة الحس، ولذلك ورد في صفته العالي والعلي والـمتعالي ، ولـم يرد ضد ذلك وإن كان قد أحاط بكل شىءٍ علـماً');

-- source: https://islamsunnite.net/limam-al-kawthari-dit-que-la-ayah-layca-kamithlihi-chay-exempte-allah-de-la-direction/
INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’Imâm Al-Kawthari dit que la âyah {Layça kamithlihi chay} exempte Allâh de la direction', 'Les Hanafites', 'قوله سبحانه { لَيْسَ كَمِثْلِهِ شَىءٌ} [ سورة الشورى / 11] نصٌّ في نفي الجهة عنه تعالى ، إذ لو لـم تنف عنه الجهة لكانت له أمثال لا تحصى ، تعالى الله عن ذلك', '« Sa parole soubhânah : {لَيْسَ كَمِثْلِهِ شَيْءٌ} (layça kamithlihi chay) [soûrat Ach-Choûrâ / 11] qui signifie : « Rien n’est tel que Lui » est un texte qui exempte Allâh de la direction, ta’âlâ. En effet, s’Il n’était pas exempt de la direction Il aurait des semblables innombrables, gloire à Allâh Qui en est exempt ».', '', 'L’assistant du dernier Calife des musulmans, l’Imâm Al-Kawthari a dit dans son commentaire du livre de l’Imâm Taqiyyou d-Dîn as-Soubki « As-Sayfou s-Saqîl » (page 88 de cette édition) :
Informations utiles :
– L’Imâm, le Mouhaddith (spécialiste de la science du hadîth), le Chaykh Mouhammad Zâhid Al-Kawthari Al-Hanafi était l’assistant du dernier Calife des musulmans (le Califat a pris fin en 1924). Il était un grand savant Hanafite qui a même été appelé par certains le « Moujaddid » du siècle dernier (c’est-à-dire celui qui revitalise la science de la religion). Il est né en 1296 et il est décédé en 1371 de l’Hégire (رحمه الله), c’est-à-dire il y a plus de 70 ans.
Le Chaykh Al-Qoudâ’i Al-’Azzâmi a dit de lui : « Al-‘Allâmah (l’illustre savant) scrupuleux, qui est très intelligent, le vérificateur, l’éminent enseignant (al-Oustâdh al-Kabîr), le Chaykh Mouhammad Zâhid Al-Kawthari » [Al-Fourqân]
– Ici, l’Imâm Al-Kawthari dit que le verset « Layça kamithlihi chay » (qui signifie : « Rien n’est tel que Lui ») [Soûrat Ach-Choûrâ / 11] exempte Allâh de la direction. Voici la croyance du dernier califat musulman, en accord avec la croyance des musulmans du Salaf et du Khalaf.', 'allah, aqida, book, califa'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'قوله سبحانه { لَيْسَ كَمِثْلِهِ شَىءٌ} [ سورة الشورى / 11] نصٌّ في نفي الجهة عنه تعالى ، إذ لو لـم تنف عنه الجهة لكانت له أمثال لا تحصى ، تعالى الله عن ذلك');

-- source: https://islamsunnite.net/le-prophete-distingue-la-bonne-innovation-de-la-mauvaise-innovation-rapporte-par-mouslim/
INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'la bonne innovation selon le prophète.', 'Mouslim', 'مَنْ سَنَّ فِى الإِسْلامِ سُنَّةً حَسَنَةً فَلَهُ أَجْرُهَا وَأَجْرُ مَنْ عَمِلَ بِهَا بَعْدَهُ مِنْ غَيْرِ أَنْ ينْقُصَ مِنْ أُجُورِهِمْ شَىْءٌ ، وَمَنْ سَنَّ فِى الإِسْلام سُنَّةً سَيِّئَةً كَانَ عَلَيْهِ وِزْرُهَا وَوِزْرُ مَنْ عَمِلَ بِهَا مِنْ بَعْدِهِ مِنْ غَيْرِ أَنْ ينْقصَ مِنْ أَوْزَارِهِمْ شَىْءٌ', '', '', 'L’Imâm Mouslim a rapporté dans son Sahîh, du Hadîth de Jarîr Ibnou ‘Abdi l-Lâh Al-Bajaliyy (رضي الله عنه) qui a dit :
« Le Messager de Allâh (صلى الله عليه وسلم) a dit :
Ce qui a pour sens : « Celui qui instaure dans l’Islâm une bonne tradition (sounnah) en aura la récompense et l’équivalent de la récompense de ceux qui œuvreront avec après lui, sans que leurs récompenses ne soient diminuées en rien ; et celui qui instaure dans l’Islâm une mauvaise tradition (sounnah) se chargera de son péché et de l’équivalent du péché de ceux qui œuvreront avec après lui, sans que leurs péchés ne soient diminués en rien. »
Informations utiles :
– L’Imâm, le Hâfidh (spécialiste de la science du hadîth) Mouslim Ibnou Al-Hajjâj Ibnou Mouslim Al-Qouchayri An-Nayçâboûri, l’auteur du célèbre recueil de Hadîth authentique (sahîh) connu sous le nom de « Sahîh Mouslim » est né en 202 et il est décédé en 261 de l’Hégire (رحمه الله) c’est-à-dire il y a plus de 1170 ans. Il est une référence incontournable dans la science du Hadîth.
– Il a cité cela dans son sahîh dans le livre de Az-Zakâh : chapitre l’incitation à l’aumône, même d’une moitié d’une datte ou d’une bonne parole et qu’elle est un écran contre le feu. Ainsi que le livre de la science : chapitre celui qui instaure dans l’Islam une bonne tradition ou une mauvaise tradition et qui appelle à la bonne guidée ou à l’égarement.
– Ce hadîth a également été rapporté en des termes proches par de nombreux autres savants du hadîth tels que :
L’Imâm At-Tirmidhi
L’Imâm Ibnou Mâjah
L’Imâm An-Naçâ-i
L’Imâm Ibnou Hibbân
L’Imâm Ahmad Ibn Hambal
L’Imâm At-Tabarâni
L’Imâm Ibn Abî Chaybah
L’Imâm Al-Bayhaqi
L’Imâm Al-Baghawi
Et autres qu’eux.
– Ce Hadîth sahîh nous indique que l’innovation (al-bid’ah) se classe en deux catégories :
La première sorte : la bonne innovation (bid’ah haçanah, appelée aussi : sounnah haçanah), c’est la nouveauté qui est en accord avec le Qour-ân et la Sounnah.
La deuxième sorte : la mauvaise innovation (bid’ah sayyi-ah, appelée aussi : sounnah sayyi-ah), c’est la nouveauté qui est en contradiction avec le Qour-ân et la Sounnah.
– Parmi les savants qui ont tirés de ce hadîth qu’il existe des bonnes innovations, il y a l’Imâm Al-Qourtoubi (رحمه الله), l’Imâm An-Nawawi (رحمه الله) [ Charh Sahîh Mouslim ] et autres qu’eux [ceci fera l’objet d’articles (إن شاء الله) ]
– Si quelqu’un prétend que ce hadîth vise ce qui est instauré du vivant du Prophète (صلى الله عليه وسلم), mais qu’après sa mort ce hadîth ne s’applique pas, on lui répond : « La spécificité n’est confirmée que par une preuve ». Or il n’y a pas ici de preuve pour cette prétendue spécificité. Au contraire, la preuve démontre le contraire de ce qu’il prétend parce que le Messager de Allâh (صلى الله عليه وسلم) a dit (ce qui a pour sens) : « Celui qui instaure dans l’Islâm » et il n’a pas dit : « Celui qui instaure de mon vivant » et il n’a pas dit : « Celui qui fait quelque chose que moi j’ai fait et qui renouvelle cet acte par la suite ». De plus, l’Islâm n’est pas limité à l’époque où le Prophète (صلى الله عليه وسلم) était vivant. Leur prétention est donc annulée.
– S’ils disent : la cause du hadîth est que des hommes très pauvres, s’habillant de vêtements de laine et de poils, sont venus auprès du Prophète (صلى الله عليه وسلم), le visage du prophète a alors changé, à la vue de leur extrême pauvreté et de leur difficulté. Les gens ont commencé alors à faire des aumônes jusqu’à ce qu’ils leur aient rassemblé beaucoup de choses. Alors le Prophète (صلى الله عليه وسلم) s’est réjoui et a dit (ce qui a pour sens) : « Celui qui instaure dans l’Islâm une bonne tradition (sounnah) en aura la récompense et l’équivalent de la récompense de ceux qui œuvreront avec après lui … » . La réponse est donc de leur dire : « ce dont on tient compte, c’est la généralité du terme et non pas la spécificité de la cause pour laquelle le hadîth a été dit » comme l’ont spécifié les savants de la science de la croyance.
– Et s’il disent que le prophète (صلى الله عليه وسلم) a dit dans un autre Hadîth rapporté par Mouslim » وكل بدعة ضلالة » (wa koullou bid’atin dalâlah), la réponse est de leur de dire que le prophète (صلى الله عليه وسلم) ne se contredit pas, c’est-à-dire qu’il n’est pas possible qu’il est prononcé deux jugements religieux qui se contredisent. Ce qui est visé par « koullou » dans ce Hadîth est « la plupart » des innovations comme l’ont expliqués les savants de l’Islam. [ Voir la citation de l’Imâm An-Nawawi à ce sujet : ici ]
– Consultez d’autres articles concernant les bonnes innovations : ici .', 'ahlou s-sounnah, allah, aqida, athar'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'مَنْ سَنَّ فِى الإِسْلامِ سُنَّةً حَسَنَةً فَلَهُ أَجْرُهَا وَأَجْرُ مَنْ عَمِلَ بِهَا بَعْدَهُ مِنْ غَيْرِ أَنْ ينْقُصَ مِنْ أُجُورِهِمْ شَىْءٌ ، وَمَنْ سَنَّ فِى الإِسْلام سُنَّةً سَيِّئَةً كَانَ عَلَيْهِ وِزْرُهَا وَوِزْرُ مَنْ عَمِلَ بِهَا مِنْ بَعْدِهِ مِنْ غَيْرِ أَنْ ينْقصَ مِنْ أَوْزَارِهِمْ شَىْءٌ');

-- source: https://islamsunnite.net/limam-al-qourtoubi-explique-pourquoi-nous-levons-nos-mains-vers-le-ciel-dans-nos-invocations/
INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Pourquoi levons nous les mains vers le ciel lors des invocations ?', 'Qourtoubi', 'وإنَّما ترفع الأيدي بالدعاء إلى السماء لأنَّ السَّماء مهبط الوحي ومنـزل القطر ومحل القُدس (أي الطهر) ومعدن الـمطهَّرين من الـملائكة ، وإليها ترفع أعمال العباد ، وفوقها عرشه وجنته ، كما جعل الله الكعبة قِبلةً للدعاء والصلاة ، ولأنه خلق الأمكنة وهو غير محتاج إليها ، وكان في أزله قبل خلق الـمكان والزمان ولامكان له ولازمان ، وهو الآن على ما عليه كان', '« Nous levons les mains vers le ciel dans les invocations car c’est du ciel que descendent la révélation et la pluie, c’est un lieu qui est sacré, purifié et c’est le lieu de résidence pour des anges purs, c’est vers le ciel que sont élevés les actes des esclaves et au-dessus du ciel qu’il y a le Trône et le Paradis, de la même manière que Allâh a fait de la Ka’bah une qiblah – une direction– pour les invocations et les prières. En effet, Il a créé les endroits et n’en a pas besoin et Il existe de toute éternité avant la création des endroits et du temps, Il n’a pas d’endroit ni d’époque et Il est maintenant tel qu’Il est de toute éternité ».', '', 'Dans son célèbre tafsîr, lors de l’explication du verset 16 de Soûrat Al-Moulk (tome 18 page 216 de cette édition), l’Imâm Al-Qourtoubi a dit :
Informations utiles :
– Le Moufassir (exégète) Mouhammad Ibnou Ahmad Al-Ansâri Al-Qourtoubi est décédé en 671 de l’Hégire (رحمه الله) c’est-à-dire il y a plus de 760 ans. Il est du madh-hab (Ecole de jurisprudence) de l’Imâm Mâlik. Son tafsîr « Al-Jâmi’ou li Ahkâmi l-Qour-ân » est une référence incontournable.
Adh-Dhahabi a dit à son sujet : « L’illustre savant (Al-‘Allâmah) […] un Imâm très intelligent, un érudit dans la science, il est l’auteur de nombreux ouvrages qui sont très utiles et qui indiquent sa grande connaissance, et l’abondance de sa vertu » [Târîkhou l-Islâm]
Ibnou Farhoûn al-Mâliki a dit de lui : « Le Chaykh, l’Imâm […] le moufassir (exégète), Il était parmi les esclaves vertueux de Allâh, de parmi les savants , les connaisseurs, les pieux, les détachés du bas-monde, ceux qui sont occupé par les affaires qui concernent l’au-delà. » Et il a dit au sujet de son Tafsîr (exégèse du Qour-ân) : « Il compte parmi les tafsîr les plus importants et les plus éminents en terme de mérite » [Ad-Dîbâj]
Ibnou ‘Imâd al-Hambali a dit : « Il était un Imâm, un savant, de parmi ceux qui ont une grande connaissance du hadîth, auteur de bons ouvrages » [Chadharâtou dh-Dhahab]
Mouhammad Makhloûf a dit à son sujet : « Le savant, l’Imâm, le glorieux (al-jalîl), le vertueux (al-fâdil), le spécialiste de la jurisprudence (faqîh), le spécialiste de l’explication du Qour-ân (moufassir), le pieux, celui qui est scrupuleux, celui qui est complet, il était parmi les esclaves vertueux de Allâh et de parmi les savants qui ont le plus de science » [Chajaratou n-Noûr]
Az-Zirikli a dit de lui : « Il est de parmi les plus grands des moufassiroûn (exégètes du Qour-ân), il était vertueux, et pieux» [Al-A’lâm]
– Ici, il explique que nous levons nos mains vers le ciel lors de nos invocations car le ciel est un lieu honoré; et que ceci ne signifie pas que Allâh est dans le ciel ou dans la direction du haut contrairement à ce qu’ont prétendu certains assimilationnistes; tout comme nous nous orientons vers la Ka’bah pour les invocations et les prières sans avoir pour croyance que Allâh est dans la Ka’bah.
– D’ailleur, il a été rapporté dans un Hadîth sahîh rapporté par Mouslim, qu’un jour le Messager de Allâh (صلى الله عليه وسلم) a fait une invocation avec les paumes de ses mains orientées vers le sol. Cela ne signifie pas, non plus, que Allâh est dans la direction du bas ou dans la terre. [ Voir l’article à ce sujet : ici ]
– De nombreux savants ont tenus des propos similaires à ceux de l’Imâm Al-Qourtoubi. Parmi eux :
L’Imâm de Ahlou s-Sounnah, Aboû Mansoûr Al-Mâtourîdi (m.333 H.) a dit : « Quant au sens de l’élévation des mains vers le ciel, ce geste est fait à titre d’adoration. En effet, il appartient à Allâh d’ordonner à Ses esclaves de L’adorer comme Il le veut et de les orienter vers la direction qu’Il veut. La croyance de celui qui a pensé qu’on lève les yeux vers le ciel parce que Allâh serait dans cette direction est équivalente à la croyance, entre autres, de celui qui prétend que Allâh est en direction du sous-sol du fait qu’il pose son front par terre en s’orientant dans la prière. C’est comme la croyance de celui qui prétend que Allâh se trouve à l’Est ou à l’Ouest lorsqu’il s’oriente dans ces directions dans la prière ou en direction de La Mecque quand il se rend au pèlerinage. Gloire à Allâh Qui est exempt de tout cela » [Dans son livre Kitâb at-Tawhîd]
L’Imâm Aboû Is-hâq Ach-Chîrâzi (m.476 H.) a dit « Allâh a fait que le ciel soit la qiblah des invocations et Allâh ‘azza wa jall n’y est pas incarné » [Dans son livre Al-Ichârah ilâ madh-hab ahli l-Haqq]
L’Imâm Aboû Sa’îd Al-Moutawalli (m.478 H.) a dit : « Le fait qu’on lève les mains lors des invocations ce n’est pas parce que Allâh serait dans un endroit , mais parce que le ciel est la qiblah des invocations tout comme la Ka’bah est la qiblah pour la prière » [Dans son livre Al-Ghounyah fî Ousoûli d-Dîn]
L’Imâm Al-Ghazâli (m.505 H.) a dit : « Le fait qu’on lève les mains lors des demandes (invocations) dans la direction du ciel c’est parce qu’il s’agit de la qiblah des dou’â » [Dans son livre Ihyâou ‘Ouloûmi d-Dîn]
L’Imâm Abou l-Mou’în An-Naçafi (m.508 H.) a dit : « Le fait de lever les mains et les visages lors des invocations, ceci est une adoration similaire au fait de s’orienter vers la Ka’bah lors des prières. Ainsi le ciel est la qiblah des invocations tout comme la maison [sacrée -c’est-à-dire la Ka’bah-] est la qiblah des prières » [Rapporté de lui par l’Imâm Az-Zabîdi dans son livre It-hâfou s-Sâdati l-Mouttaqîn et par le Chaykh Moullâ ‘Ali Al-Qârî dans son livre Charh Fiqh Al-Akbar]
Le Chaykh Charafou d-Dîn Ibn At-Tilimçâni (m.658 H.) a dit : « Quant au fait qu’on lève nos mains vers le ciel, c’est parce qu’il s’agit de la qiblah des invocations, tout comme la ka’bah est la qiblah de la prière, et il s’agit également de l’endroit d’où descend la révélation » ; et il a dit avant cela, pour dénoncer la croyance des mouchabbihah (assimilationnistes) : « Ils (les assimilationnistes) ont dit que le fait qu’on lève nos mains vers le ciel lors de nos demandes et invocations indique [pour Allâh] la direction » [Charh louma’ Al-Adillah]
L’Imâm An-Nawawi (m.676 H.) a dit : « Allâh est Celui pour lequel ceux qui font des invocations lèvent leurs mains vers le ciel, de la même façon que celui qui prie se dirige vers la Ka’bah; et ce n’est pas parce qu’Il serait localisé dans (ou au-dessus) le ciel, de même qu’Il n’est pas localisé dans la direction de la Ka’bah, mais il en est ainsi parce que le ciel est la qiblah de ceux qui font des invocations, et la Ka’bah est la direction de ceux qui prient » [ Charh Sahîh Mouslim ]
L’Imâm Mahmoûd Al-Qoûnawi Al-Hanafi (m.771 H.) a dit : « Le fait de lever les mains et les visages vers le ciel lors des invocations est fait à titre d’adoration, tout comme le fait de se diriger vers la Ka’bah pour la prière. Ainsi, le ciel est la qiblah des invocations, tout comme la Maison [sacrée – c’est-à-dire la Ka’bah] est la qiblah de la prière » [Al-Qalâ-id fî Charh Al-‘Aqâ-id]
L’Imâm Ibnou Hajar Al-‘Asqalâni (m.852 H.) rapporte que l’Imâm Ibnou Battâl (m.449 H.) a dit : « Le ciel est la qiblah des invocations tout comme la Ka’bah est la qiblah pour la prière» [Dans son livre Fat-hou l-Bârî]
Le Chaykh Moullâ ‘Ali Al-Qârî (m. 1014 H.) a dit : « Le ciel est la qiblah des invocations » [Dans son livre Charh Fiqh Al-Akbar]
L’Imâm Al-Bayâdi Al-Hanafi (m.1098 H.) a dit : « Le fait qu’on lève les mains lors de nos invocations dans la direction du ciel ce n’est parce que Allâh ta’âlâ serait au-dessus des cieux mais parce que le ciel est la qiblah des dou’â » [Dans son livre Ichâratou l-Marâm]
L’Imâm, le Hâfidh Mourtadâ Az-Zabîdi (m.1205 H.) a dit : « Certes le ciel a été spécifié par le fait qu’on lève les mains vers lui lors de nos invocations, car il est la qiblah des invocations, tout comme la Ka’bah est la qiblah de ceux qui prient afin qu’ils s’y orientent lors de leurs prières. Et on ne dit pas que Allâh serait dans la direction de la Ka’bah » [Dans son livre It-hâfou s-Sâdati l-Mouttaqîn]
Le Moufti de La Mecque le Chaykh Ahmad Ibn Zayni Dahlân rapporte de Abou l-Qâçim As-Samarqandi qu’il a dit : « Le fait de lever les mains est la qiblah des invocations tout comme la Ka’bah est la qiblah pour la prière» [Dans son livre Ad-Dourarou s-Saniyyah fî Raddi ‘ala l-Wahhâbiyyah]
Le Chaykh Moustafâ Wahîb Al-Bâroûdi At-Tarâboulçi (m.1373 H.) a dit similaire à l’Imâm Al-Ghazâli : « Le fait qu’on lève les mains lors des demandes (invocations) dans la direction du ciel c’est parce qu’il s’agit de la qiblah des dou’â » [Dans son livre Al-Fawzou l-Abdî]
Le Mouhaddith ‘Abdou l-Lâh Al-Harari (m.1439 H.) a dit : « Le fait de lever les mains et les visages lors des invocations, ceci est une adoration similaire au fait de s’orienter vers la Ka’bah lors des prières. Ainsi le ciel est la qiblah des invocations tout comme la maison [sacrée -c’est-à-dire la Ka’bah-] est la qiblah des prières » [Dans son livre Idh-hârou l-‘Aqîdah as-Sounniyyah]
Le Chaykh, le Docteur Samîr Al-Qâdî a dit : « Le ciel est la qiblah des invocations » [Dans son livre Noûrou s-Sirât al-Moustaqîm]
– Vous pouvez consulter d’autres paroles de savants sur ce sujet : ici .
– Ainsi il ne convient pas de prêter attention aux propos des wahhabites qui prétendent que si nous levons nos mains vers la direction du haut lors de nos invocations ça serait parce que Allâh serait – d’après eux – dans le ciel. Ces propos contraires au tawhîd ont été tenus entre autre par Ibn ‘Outhaymîn (wahhabite) dans son commentaire du livre Riyâd as-Sâlihîn dans lequel il a osé dire : « Même ceux qui nient que Allâh est au ciel [l’unanimité des musulmans], que Allâh nous guide ainsi que eux, s’ils veulent invoquer, vers où lèvent-ils les mains ? Au ciel, soubhâna l-Lâh. Leurs actes contredisent leur croyance, cette croyance mauvaise et erronée qui risque de causer leur mécréance ». On remarque également qu’il est de l’habitude des wahhabites de commenter les ouvrages de savants dont ils contredisent la croyance, comme c’est le cas ici avec l’Imâm An-Nawawi (رحمه الله). En effet le livre Riyâd as-Sâlihîn est une œuvre de l’Imâm An-Nawawi, pourtant Ibn ‘Outhaymîn (wahhabite) l’a commenté en incluant dedans des croyances contraires à celle de l’Imâm An-Nawawi.', 'allah, aqida, book, ciel'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'وإنَّما ترفع الأيدي بالدعاء إلى السماء لأنَّ السَّماء مهبط الوحي ومنـزل القطر ومحل القُدس (أي الطهر) ومعدن الـمطهَّرين من الـملائكة ، وإليها ترفع أعمال العباد ، وفوقها عرشه وجنته ، كما جعل الله الكعبة قِبلةً للدعاء والصلاة ، ولأنه خلق الأمكنة وهو غير محتاج إليها ، وكان في أزله قبل خلق الـمكان والزمان ولامكان له ولازمان ، وهو الآن على ما عليه كان');

