INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’ancien Moufti d’Egypte Mouhammad Haçanayn Makhloûf dit que Allâh est sans endroit', 'Al Azhar', 'إن الله منـزهٌ عن جميع النقائص ، وسمات الحدوث ، ومنها الزمان والـمكان ، فلا يُقارنه زمانٌ ولا يحويه مكانٌ إذ هو الخالق لهما فكيف يحتاج إليهما', 'Allâh est exempt de toute imperfection et de toutes les caractéristiques de ce qui entre en existence parmi lesquelles le temps et l’endroit. Il n’est donc pas sujet au temps et Il n’est pas contenu dans un endroit. Étant le Créateur de l’un et de l’autre, comment en aurait-Il besoin ?!', '', 'Dans son livre « Moukhtasarou Charhi ‘Aqîdati Ahli l-Islâm », l’ancien Moufti d’Egypte, le Chaykh Mouhammad Haçanayn Makhloûf a dit :
Informations utiles :
– Le Moufti d’Egypte, le Chaykh Mouhammad Haçanayn Makhloûf Al-‘Adawi Al-Mâliki, est né en 1307 et il est décédé en 1410 de l’Hégire (رحمه الله). Il était également l’un des grands Chaykh de l’université Islamique « Al-Azhar » d’Egypte.
– Ici, il dit que Allâh est le Créateur du temps et de l’endroit et que par conséquent Allâh n’en a pas besoin : Il n’est pas sujet au temps et Il n’est pas contenu dans un endroit.', 'al azhar, al-azhar, allah, aqida'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'إن الله منـزهٌ عن جميع النقائص ، وسمات الحدوث ، ومنها الزمان والـمكان ، فلا يُقارنه زمانٌ ولا يحويه مكانٌ إذ هو الخالق لهما فكيف يحتاج إليهما');

-- source: https://islamsunnite.net/le-hafidh-as-souyouti-dit-que-la-ayah-layca-kamithlihi-chay-confirme-que-allah-est-sans-endroit-et-quil-nest-pas-un-corps/
INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Le Hâfidh As-Souyoûti dit que la âyah {Layça kamithlihi chay} confirme que Allâh est sans endroit et qu’Il n’est pas un corps', 'Les Chafi''ites', 'قوله تعالى { ليس كمثله شيء } فيه الرد على المشبهة وأنه تعــــــالى ليس بجوهـــــر ولا جسم ولا عرض ولا لــــــون ولا طعم ولا حالّ في مكان ولا زمان', '« La parole de Allâh : {ليس كمثله شيء } « Layça kamithlihi chay » (qui signifie : « Rien n’est tel que Lui ») est une réfutation de la croyance des Mouchabbihah (Ceux qui assimilent Allâh à Ses créatures) et une confirmation qu’Il (Allâh) n’est pas une substance, ni un corps, ni une caractéristique d’un corps, ni une couleur, ni un goût, qu’Il n’occupe pas un endroit et qu’Il ne dépend pas du temps »', '', 'Dans son livre « Al-Iklîl fi stinbâtit-Tanzîl » (page 230 de notre édition), le Hâfidh As-Souyoûti, dans l’explication du verset 11 de Soûrat Ach-Choûrâ, a dit :
Informations utiles :
– L’Imâm, le Hâfidh (spécialiste de la science du Hadîth), le Moufassir (spécialiste de l’exégèse), le Faqîh (spécialiste de la jurisprudence), Abou l-Fadl ‘Abdou r-Rahmân ibnou Abi Bakr Jalâlou d-Dîn as-Souyoûti est un grand savant chafi’ite reconnu par toute la communauté musulmane. Il est né en 849 au Caire et il est décédé en 911 de l’hégire au Caire (رحمه الله) c’est-à-dire il y a environ 520 ans. Certains l’ont désigné comme le moujaddid du 10ème siècle de l’hégire (c’est-à-dire celui qui revitalise la science de la religion).
– Ici, il dit que le verset « Layça kamithlihi chay » (qui signifie : « Rien n’est tel que Lui ») [Soûrat Ach-Choûrâ / 11] confirme que Allâh est exempt de l’endroit, du corps, de la couleur etc… Et que ce verset est une réfutation de la croyance des Mouchabbihah (assimilationnistes).', 'ach-choura, allah, aqida, bila makan'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'قوله تعالى { ليس كمثله شيء } فيه الرد على المشبهة وأنه تعــــــالى ليس بجوهـــــر ولا جسم ولا عرض ولا لــــــون ولا طعم ولا حالّ في مكان ولا زمان');

-- source: https://islamsunnite.net/limam-al-boukhari-rapporte-que-le-prophete-a-fait-leloge-dun-compagnon-ayant-innove-une-evocation-dans-la-priere/
INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'La distinction entre bonnes et mauvaises innovations.', 'Les Chafi''ites', 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ الْمُجْمِرِ عَنْ عَلِيِّ بْنِ يَحْيَى بْنِ خَلَّادٍ الزُّرَقِيِّ عَنْ أَبِيهِ عَنْ رِفَاعَةَ بْنِ رَافِعٍ الزُّرَقِيِّ قَالَ كُنَّا يَوْمًا نُصَلِّي وَرَاءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَفَعَ رَأْسَهُ مِنْ الرَّكْعَةِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَالَ رَجُلٌ وَرَاءَهُ رَبَّنَا وَلَكَ الْحَمْدُ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ فَلَمَّا انْصَرَفَ قَالَ مَنْ الْمُتَكَلِّمُ قَالَ أَنَا قَالَ رَأَيْتُ بِضْعَةً وَثَلَاثِينَ مَلَكًا يَبْتَدِرُونَهَا أَيُّهُمْ يَكْتُبُهَا أَوَّلُ', '« Rifâ’ah Ibnou Râfi’ Az-Zouraqi a dit : Nous étions un jour en train de faire la prière dirigés par le Prophète (صلى الله عليه وسلم) ; quand il a levé sa tête de l’inclination, il a dit : {سَمِعَ اللهُ لِمَنْ حَمِدَهُ} « sami’a l-Lâhou liman hamidah » (ce qui a pour sens : « Allâh accepte les louanges de celui qui Le loue »). Un homme derrière lui a dit : (Rabbanâ wa laka l-hamd, hamdan kathîran, tayyiban moubârakan fîh). Quand il a fini la prière et qu’il s’apprêtait à partir, le Prophète (صلى الله عليه وسلم) a dit : {مَن المُتَكَلَّمُ} ce qui a pour sens : « Qui a parlé ? ». Il a dit : « C’est moi ». Le Prophète (صلى الله عليه وسلم) a dit :', '', 'L’Imâm Al-Boukhâri a rapporté dans son Sahîh, ce hadîth :', 'al boukhari, al-bokhari, al-boukhariyy, al-bukhari'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ الْمُجْمِرِ عَنْ عَلِيِّ بْنِ يَحْيَى بْنِ خَلَّادٍ الزُّرَقِيِّ عَنْ أَبِيهِ عَنْ رِفَاعَةَ بْنِ رَافِعٍ الزُّرَقِيِّ قَالَ كُنَّا يَوْمًا نُصَلِّي وَرَاءَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَفَعَ رَأْسَهُ مِنْ الرَّكْعَةِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَالَ رَجُلٌ وَرَاءَهُ رَبَّنَا وَلَكَ الْحَمْدُ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ فَلَمَّا انْصَرَفَ قَالَ مَنْ الْمُتَكَلِّمُ قَالَ أَنَا قَالَ رَأَيْتُ بِضْعَةً وَثَلَاثِينَ مَلَكًا يَبْتَدِرُونَهَا أَيُّهُمْ يَكْتُبُهَا أَوَّلُ');

-- source: https://islamsunnite.net/limam-al-qourtoubi-explique-le-verset-aamintoum-man-fi-s-sama-de-sourat-al-moulk/
INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’Imâm Al-Qourtoubi explique le verset «a-amintoum man fi s-samâ » de Soûrat Al-Moulk', 'Qourtoubi', 'والـمراد بِها توقيره [مراده : تعظيمه ] وتنـزيهه عن السفل والتحت ، ووصفه بالعلوِّ والعظمة لا بالأماكن والجهات والحدود لأنَّها صفات الأجسام', '« Ce qui est visé ici, c’est Sa glorification, Son exemption du bas et du dessous et Sa qualification par al-‘oulouww (l’élévation du mérite) et al-‘adhamah (l’éminence) et non pas la qualification par les endroits, les directions et les limites car ce sont des caractéristiques des corps ».', '', 'Dans son célèbre tafsîr, lors de l’explication de la parole de Allâh {ءَأَمِنتُم مَّن فِى ٱلسَّمَآءِ أَن يَخۡسِفَ بِكُمُ ٱلۡأَرۡضَ } (a-amintoum man fi s-samâ an yakhsifa bikoumou l-ard ) verset 16 de Soûrat Al-Moulk (tome 18 page 216 de notre édition), l’Imâm Al-Qourtoubi a dit :
Informations utiles :
– Le Moufassir –exégète– Mouhammad Ibnou Ahmad Al-Ansâri Al-Qourtoubi est décédé en 671 de l’Hégire (رحمه الله) c’est-à-dire il y a plus de 760 ans. Il est du madh-hab (Ecole de jurisprudence) de l’Imâm Mâlik. Son tafsîr « Al-Jâmi’ou li Ahkâmi l-Qour-ân » est une référence incontournable.
– Ici, il dit que le verset { ءَأَمِنتُم مَّن فِى ٱلسَّمَآءِ } (a-amintoum man fi s-samâ) ne signifie pas que Allâh est dans un endroit ou une direction.
– Certains ignorants des sciences du Tafsîr (Exegèse), du Tawhîd (Unicité de Allâh) et des fondements de la religion ont une compréhension erronée de ce verset et en comprennent que Allâh habiterait les cieux. Cette croyance là est contraire à l’Islâm.
– Dans son Livre « At-Tidh-kârou fî Afdali l-Adh-kâr », l’Imâm Al-Qourtoubi avait également dit que ce verset n’a pas pour sens que Allâh est dans un endroit. [ Voir l’article à ce sujet :ici ]', 'allah, aqida, book, corps'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'والـمراد بِها توقيره [مراده : تعظيمه ] وتنـزيهه عن السفل والتحت ، ووصفه بالعلوِّ والعظمة لا بالأماكن والجهات والحدود لأنَّها صفات الأجسام');

-- source: https://islamsunnite.net/le-hafidh-ibn-hajar-al-3asqalani-rapporte-lunanimite-sur-le-fait-que-allah-est-exempt-du-mouvement-du-deplacement-et-de-lincarnation/
INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'Le Hâfidh Ibn Hajar Al-‘Asqalâni rapporte l’unanimité sur le fait que Allâh est exempt du mouvement, du déplacement et de l’incarnation', 'Al Azhar', 'فمعتقد سلف الأئمة وعلـماء السنة من الخلف أن الله منـزه عن الحركة والتحول والحلول ، ليس كمثله شىء', '« La croyance du Salaf, des Imams et des savants de la Sounnah du Khalaf, c’est que Allâh est exempt du mouvement, du déplacement et de l’incarnation. Rien n’est tel que Lui ».', '', 'Dans son commentaire du Sahîh de Al-Boukhâri «Fath Al-Bârî » (tome 7 p 124 de cette édition), l’Imâm Ibnou Hajar Al-‘Asqalâni a dit :
Informations utiles :
– Chaykhou l-Islâm, Amîr al-Mouminîn fi l-hadîth (le Prince des croyants dans la science du hadîth) Chihâb ad-Dîn Abou l-Fadl Ahmad Ibnou ‘Ali Ibnou Hajar Al-‘Asqalâni est né en 773 et il est décédé en 852 de l’hégire (رحمه الله) c’est-à-dire il y a plus de 590 ans. C’est un très grand spécialiste de la science du hadîth qui a écrit de nombreux ouvrages. Il est du madh-hab (Ecole de jurisprudence) de l’Imam Ach-Châfi’i. Son livre « Fath Al-Bârî » est incontournable, c’est le plus célèbre commentaire du Sahîh Al-Boukhâri. Consultez sa biographie : ici .
– Ici, il rapporte l’unanimité sur le fait que Allâh est exempt du mouvement, du déplacement et de l’incarnation. Et il précise que cela est la croyance des gens du Salaf (des musulmans des trois premiers siècles de l’Hégire), comme du Khalaf (les musulmans qui ont succédé aux gens du Salaf) par unanimité.
– L’unanimité (ijmâ’) est une preuve dans la religion. En effet le prophète (صلى الله عليه وسلم) nous a enseigné que les savants de sa communauté ne seront jamais unanimes sur un égarement, par sa parole « إنّ أُمَّتي لا تجتمع على ضلالة » ce qui a pour sens : « Ma communauté ne sera jamais unanime sur un égarement. » [Hadîth sahîh (authentique) rapporté selon différentes versions par Al-Hâkim, At-Tirmidhi, Ibnou Mâjah, Aboû Dâwoûd et autres en des termes proches]. A ce sujet :
L’Imâm Al-Jouwayni a dit : « L’unanimité (Ijmâ’) de cette communauté (Oummah) est une preuve à elle seule, en raison de la parole du prophète : “لا تجتمع أمتي على ضلالة” [ce qui a pour sens : ] ma communauté ne sera jamais unanime sur un égarement » [Al-Waraqât]
L’Imâm An-Nawawi a dit : « Les fondements de la religion sont quatre : le Livre (le Qour-ân), la Sounnah, l’unanimité (ijmâ’) et le Qiyâs (des savants moujtahid).» [Al-Maqâçid]
Le Moufti de La Mecque, le Chaykh Ahmad Ibnou Zayni Dahlân a dit : « L’unanimité de la Oummah est une preuve dans la religion, comme l’a indiqué le prophète : “لا تجتمع أمتي على ضلالة” [ce qui a pour sens : ] ma communauté ne sera jamais unanime sur un égarement » [Dans son livre Fitnatou l-Wahhâbiyyah]', '3asqalani, allah, aqida, asqalani'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'فمعتقد سلف الأئمة وعلـماء السنة من الخلف أن الله منـزه عن الحركة والتحول والحلول ، ليس كمثله شىء');

