WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = 'والناس فيها وفيما شاكلها على ثلاثة أوجه قال بعضهم : نقرؤها ونؤمن بها ولا نفسرها ، وذهب إليه كثير من الأئمة ، وهذا كما روي عن مالك رحمه الله أن رجلا سأله عن قوله تعالى : الرحمن على العرش استوى ، قال مالك : الاستواء غير مجهول ، والكيف غير معقول ، والإيمان به واجب ، والسؤال عنه بدعة ، وأراك رجل سوء أخرجوه . وقال بعضهم : نقرؤها ونفسرها على ما يحتمله ظاهر اللغة . وهذا قول المشبهة . وقال بعضهم : نقرؤها ونتأولها ونحيل حملها على ظاهرها');

