INSERT INTO "parole" (sujet, savant, texte_arabe, texte_francais, phonétique, explication, tag)
SELECT 'L’Imâm An-Nawawi et les bonnes innovations.', 'Nawawi', '« قوله صلى الله عليه وسلم : ( وكل بدعة ضلالة ) هذا عام مخصوص ، والمراد غالب البدع .', '', '', 'L’Imâm An-Nawawi, dans son charh (commentaire) du Sahîh Mouslim (tome 6 pages 154-155 de cette édition) lorsqu’il a commenté le hadîth qui contient la phrase « koullou bid’atin dalâlah wa koullou dalâlatin fi n-nâr » qui signifierait selon le sens apparent « Toute innovation est égarement et tout égarement est au feu », il a dit :', 'ahlou s-sounnah, allah, aqida, bid3a'
WHERE NOT EXISTS (SELECT 1 FROM "parole" WHERE texte_arabe = '« قوله صلى الله عليه وسلم : ( وكل بدعة ضلالة ) هذا عام مخصوص ، والمراد غالب البدع .');

